// C3: Physical Sensing Components
instance MotorRotationEncoder : DTDFVocab:SensingComponent [
    base:desc "Position encoder mounted on the permanent‑magnet synchronous motor shaft of the first rotary axis"
    DTDFVocab:producedData MotorAngleData
]

instance GearRotationEncoder : DTDFVocab:SensingComponent [
    base:desc "Redundant position encoder mounted on the planetary gear output of the first rotary axis"
    DTDFVocab:producedData GearAngleData
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor measuring the electrical current I_M of the motor on the first rotary axis"
    DTDFVocab:producedData CurrentSignalData
]

// C4: Physical‑to‑Virtual Interaction (Data Transmitted)
instance MotorAngleData : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorRotationEncoder
]

instance GearAngleData : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearRotationEncoder
]

instance CurrentSignalData : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// C10: Models/Data (Computed Derived Data)
instance ComputedMotorTorque : DTDFVocab:Data [
    base:desc "Computed torque τ for the motor calculated from raw sensor streams"
    DTDFVocab:fromData MotorAngleData
    DTDFVocab:inputTo DataProcessingComponent
]

instance ComputedMotorVelocity : DTDFVocab:Data [
    base:desc "Computed angular velocity ω for the motor derived from raw sensor streams"
    DTDFVocab:fromData MotorAngleData
    DTDFVocab:inputTo DataProcessingComponent
]

instance ComputedGearTorque : DTDFVocab:Data [
    base:desc "Computed torque τ for the planetary gear located on the first rotary axis"
    DTDFVocab:fromData GearAngleData
    DTDFVocab:inputTo DataProcessingComponent
]

instance ComputedGearVelocity : DTDFVocab:Data [
    base:desc "Computed angular velocity ω for the planetary gear derived from raw sensor streams"
    DTDFVocab:fromData GearAngleData
    DTDFVocab:inputTo DataProcessingComponent
]

instance ComputedSystemTorque : DTDFVocab:Data [
    base:desc "Computed torque τ for the system output of the first rotary axis"
    DTDFVocab:fromData CurrentSignalData
    DTDFVocab:inputTo DataProcessingComponent
]

instance ComputedSystemVelocity : DTDFVocab:Data [
    base:desc "Computed angular velocity ω for the system output of the first rotary axis"
    DTDFVocab:fromData CurrentSignalData
    DTDFVocab:inputTo DataProcessingComponent
]

// C11: Enablers
instance DataProcessingComponent : DTDFVocab:Enabler [
    base:desc "Processing component that consumes raw sensor streams, executes models, and updates services"
    DTDFVocab:enables VisualDashboardService, FrictionModelUpdateService, SimulationExecutionService, ComparisonAnalysisService, ControllerRefinementService
]

// C6: Services
instance VisualDashboardService : DTDFVocab:Service [
    base:desc "Provides real‑time visualization of motor, gear, and system dynamics through a unified dashboard"
    DTDFVocab:provides RealTimeVisualizationInsight
]

instance FrictionModelUpdateService : DTDFVocab:Service [
    base:desc "Continuously identifies and updates white‑box friction models (Coulomb‑Viscous, Stribeck, Dahl, LuGre)"
    DTDFVocab:provides FrictionModelUpdateInsight
]

instance SimulationExecutionService : DTDFVocab:Service [
    base:desc "Runs Simulink simulations of the motor and gearbox behavior for the first rotary axis"
    DTDFVocab:provides SimulationAccuracyInsight
]

instance ComparisonAnalysisService : DTDFVocab:Service [
    base:desc "Performs live‑time comparison between measured and simulated outputs to diagnose friction loss"
    DTDFVocab:provides ComparisonResultInsight
]

instance ControllerRefinementService : DTDFVocab:Service [
    base:desc "Supplies computed friction parameters and simulation results for controller refinement"
    DTDFVocab:provides ControllerRefinementInsight, FeedBackFrictionParamsAction
]

// C17: Insights
instance RealTimeVisualizationInsight : DTDFVocab:Insight [
    base:desc "Displays real‑time plots of computed torque and angular velocity for the motor, gear, and system"
]

instance FrictionModelUpdateInsight : DTDFVocab:Insight [
    base:desc "Indicates continuous identification and dynamic updating of white‑box friction models"
]

instance SimulationAccuracyInsight : DTDFVocab:Insight [
    base:desc "Assesses the accuracy of Simulink motor and gearbox models compared to measured data"
]

instance ComparisonResultInsight : DTDFVocab:Insight [
    base:desc "Highlights differences between measured and simulated outputs to diagnose friction loss"
]

instance ControllerRefinementInsight : DTDFVocab:Insight [
    base:desc "Provides computational results facilitating controller refinement"
]

// C17: Actions
instance FeedBackFrictionParamsAction : DTDFVocab:Action [
    base:desc "Feeds extracted friction parameters back into the robot controller for enhanced motion precision"
    DTDFVocab:IsAutomatic true
]

// C10: Models
instance SysMLMotorModel : DTDFVocab:Model [
    base:desc "SysML component diagram representing the permanent‑magnet synchronous motor of the first rotary axis"
    DTDFVocab:inputTo DataProcessingComponent
]

instance SysMLGearbox1Model : DTDFVocab:Model [
    base:desc "SysML component diagram representing the planetary gearbox on the first rotary axis"
    DTDFVocab:inputTo DataProcessingComponent
]

instance SysMLGearbox2Model : DTDFVocab:Model [
    base:desc "SysML component diagram representing the cycloidal gearbox on the first rotary axis"
    DTDFVocab:inputTo DataProcessingComponent
]

instance SimulinkMotorSim : DTDFVocab:Model [
    base:desc "MATLAB/Simulink executable model for motor behavior simulation"
    DTDFVocab:inputTo DataProcessingComponent
]

instance SimulinkGearboxSim : DTDFVocab:Model [
    base:desc "MATLAB/Simulink executable model for gearbox behavior simulation"
    DTDFVocab:inputTo DataProcessingComponent
]

// C3: Physical components (for structure)
instance MotorComponent : DTDFVocab:Component [
    base:desc "Permanent‑magnet synchronous motor of the first rotary axis"
]

instance Gearbox1Component : DTDFVocab:Component [
    base:desc "Planetary gear transmission of the first rotary axis"
]

instance Gearbox2Component : DTDFVocab:Component [
    base:desc "Cycloidal gearbox of the first rotary axis"
]

instance DigitalShadow : DTDFVocab:Component [
    base:desc "Digital twin shadow representing the first rotary axis of the MABI MAX 100 robot"
]

// C17: Environment
instance DigitalTwinEnvironment : DTDFVocab:Environment [
    base:contains DigitalShadow, MotorComponent, Gearbox1Component, Gearbox2Component, DataProcessingComponent
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Real‑time streaming and processing synchronized with the robot’s control cycle. Sensor data are ingested and processed within the same timeframe as the controller update, enabling immediate friction estimation and visualization."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A single DT entity composed of: (1) Asset configuration (MABI MAX 100 first axis) represented by AAS; (2) Engineering models (SysML structural/behavior); (3) Data‑calculation and simulation models (Simulink); (4) Data traces (measured and simulated); (5) Processing component that consumes input traces, applies models, and outputs derived traces; (6) Dashboard for visualization. All components interact through the AAS and MQTT.
"
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The DT spans from design (ideal friction‑free simulation models) to manufacturing (actual plant with embedded encoders) and to operation (continuous runtime identification). It therefore covers the ‘operated’ life‑cycle stage, with continuous model adaptation during use."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "White‑box (analytical) friction models capture physical phenomena (load, temperature, time) but require parameter identification; black‑box models bypass this. The DT maintains traceability of each simulated data point to its source model and input data, allowing verification against measured traces. Continuous identification mitigates drift due to wear or tooling changes, improving validity over time.
"
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Communication between PT and DT employs the MQTT protocol over a standard IP network, delivering sensor streams to the DT data acquisition component.
"
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Asset Administration Shell (AAS) as the standard interface for digital twins; SysML as a standard MBSE modeling language; MQTT conforms to open messaging protocols."
]
